'use strict';

module.exports = function applyDefaultsToPOJO(doc, schema) {
  const paths = Object.keys(schema.paths);
  const plen = paths.length;

  for (let i = 0; i < plen; ++i) {
    let curPath = '';
    const p = paths[i];

    const type = schema.paths[p];
    const path = type.splitPath();
    const len = path.length;
    let doc_ = doc;
    for (let j = 0; j < len; ++j) {
      if (doc_ == null) {
        break;
      }

      const piece = path[j];
      curPath += (!curPath.length ? '' : '.') + piece;

      if (j === len - 1) {
        if (typeof doc_[piece] !== 'undefined') {
          if (type.$isSingleNested) {
            applyDefaultsToPOJO(doc_[piece], type.schema);
          } else if (type.$isMongooseDocumentArray && Array.isArray(doc_[piece])) {
            doc_[piece].forEach(el => applyDefaultsToPOJO(el, type.schema));
          }

          break;
        }

        const def = type.getDefault(doc, false, { skipCast: true });
        if (typeof def !== 'undefined') {
          doc_[piece] = def;

          if (type.$isSingleNested) {
            applyDefaultsToPOJO(def, type.schema);
          } else if (type.$isMongooseDocumentArray && Array.isArray(def)) {
            def.forEach(el => applyDefaultsToPOJO(el, type.schema));
          }
        }
      } else {
        if (doc_[piece] == null) {
          doc_[piece] = {};
        }
        doc_ = doc_[piece];
      }
    }
  }
};

// MSW v2 browser compatibility shim for @vitest/mocker
// This provides MSW v2 exports using MSW v1 APIs to maintain compatibility
// while keeping the rest of the monorepo on MSW v1

try {
  // Try to import from MSW v1
  const { setupWorker, rest } = require('msw');

  // Export in MSW v2 format expected by @vitest/mocker
  module.exports = {
    setupWorker,
    // MSW v2 uses 'http' instead of 'rest', but we provide both for compatibility
    http: rest,
    rest, // Keep rest for any MSW v1 code
  };
} catch (error) {
  // Fallback if MSW is not available - provide minimal mock
  console.warn(
    'MSW not available, providing minimal mock for @vitest/mocker compatibility',
  );
  module.exports = {
    setupWorker: () => ({
      start: () => Promise.resolve(),
      stop: () => {},
      use: () => {},
      resetHandlers: () => {},
    }),
    http: {
      get: () => {},
      post: () => {},
      put: () => {},
      delete: () => {},
      patch: () => {},
      head: () => {},
      options: () => {},
    },
    rest: {
      get: () => {},
      post: () => {},
      put: () => {},
      delete: () => {},
      patch: () => {},
      head: () => {},
      options: () => {},
    },
  };
}

